"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[141],{33414:n=>{n.exports=JSON.parse('{"functions":[{"name":"Get","desc":"Returns a hash of the current sounds that are warmed.\\n\\n```lua\\nprint(VluxySF.Cache.Get())\\n```","params":[],"returns":[{"desc":"The current sounds being Warmed.","lua_type":"{ [string]: Sound }"}],"function_type":"static","source":{"line":881,"path":"lib/init.luau"}},{"name":"IsWarmed","desc":"Tells you if a sound from its name is currently warmed.\\n\\n```lua\\nprint(VluxySF.Cache.IsWarmed(\\"MySound\\"))\\n```","params":[{"name":"soundName","desc":"Name of the `Sound`.","lua_type":"string"}],"returns":[{"desc":"Is that sound warmed?","lua_type":"boolean"}],"function_type":"static","source":{"line":901,"path":"lib/init.luau"}},{"name":"Warm","desc":"Loads the `Sound` to the Client. If the the same `Sound` is fetched it will instead `Clone` from it.\\n\\n:::warning\\nYou should only warm if you need a sound to play without a delay or to play without fail but dont plan to constantly use it.\\n:::\\n\\n:::tip\\nYou can Warm at the top of a script or a seperate script if the sound you play is in a connection or function that gets called later.\\n\\tSome examples include loading a map and its sounds in. Maybe warming the sounds when first loading the map is a good idea!?\\n:::\\n\\n```lua\\nVluxySF.Cache.Warm(\\"MySound\\") --now if its used later on it should be ready to play.\\n\\n--do stuff\\n\\ntask.wait(5)\\n\\n--do stuff\\n\\nVluxySF.FetchplayOnce(\\"MySound\\") --should play without delay now\\n```","params":[{"name":"...","desc":"Names of the `Sounds`.","lua_type":"string"}],"returns":[],"function_type":"static","source":{"line":936,"path":"lib/init.luau"}},{"name":"Chill","desc":"If a `Sound` with that name is currently warmed it is removed it from the cache.\\n\\n:::info\\nRemoving a sound from the cache does not garentee that it will be unloaded. \\nIf you still have Sounds with the same Id it will still be in memmory.\\n:::\\n\\n```lua\\n\\nVluxySF.Cache.Warm(\\"MySound\\")\\n\\nlocal onPlay = Instance.new(\\"BindableEvent\\")\\nlocal myWarmedSound = ...\\n\\nlocal function playSound()\\n\\tmyWarmedSound:Play() --plays without delay\\nend\\nOnPlay.Event:Connect(playSound)\\n\\nOnPlay.Destroying:Connect(function()\\n\\tmyWarmedSound:Destroy() --clean up our sound\\n\\tVluxySF.Cache.Chill(\\"MySound\\") -- now the sound isn\'t warmed\\nend)\\n\\n\\n--Now if OnPlay is destroyed it wont be warmed anymore.\\n--So, if the soundId isnt used anywhere else it will be removed from memmory.\\n```","params":[{"name":"...","desc":"Names of the `Sounds`.","lua_type":"string"}],"returns":[],"function_type":"static","source":{"line":980,"path":"lib/init.luau"}}],"properties":[],"types":[],"name":"Cache","desc":"Functions for warming and chilling sounds.","tags":["RequiresSchema"],"realm":["Client"],"source":{"line":868,"path":"lib/init.luau"}}')}}]);